module bin2gray_4bit (
    input wire [3:0] obf_bin_in,
    output wire [3:0] gray_out
);

    assign gray_out[3] = obf_bin_in[3];
    assign gray_out[2] = obf_bin_in[3] ^ obf_bin_in[2];
    assign gray_out[1] = obf_bin_in[2] ^ obf_bin_in[1];
    assign gray_out[0] = obf_bin_in[1] ^ obf_bin_in[0];

endmodule
